'use strict';

// ╔══════════════════════════════════════════════════════════════════════════════╗
// ║  PHARMAOS · AI PROMPT BUILDER · n8n Code Node · v5.0.0                     ║
// ║                                                                              ║
// ║  Pipeline:  SQL balanced candidates → THIS NODE → OpenRouter LLM            ║
// ║                                                                              ║
// ║  What this node does:                                                        ║
// ║  1. Ingests every signals_mesh field + all SQL-computed fields               ║
// ║  2. Loads asset registry (Merge Context) + strategy memory                   ║
// ║  3. Extracts + compresses raw_text and summary into a rich context block     ║
// ║  4. Runs 10-factor quality scoring + fingerprinting                          ║
// ║  5. Routes to the right LLM model + temperature (domain-aware)              ║
// ║  6. Constructs maximally detailed system + user prompts                      ║
// ║  7. Returns full pass-through payload + openrouter_body ready to POST        ║
// ╚══════════════════════════════════════════════════════════════════════════════╝

// ═══════════════════════════════════════════════════════════════════════════════
// §0  PIPELINE CONSTANTS
// ═══════════════════════════════════════════════════════════════════════════════

const PIPELINE_VERSION   = '5.0.0';
const MAX_CONTEXT_CHARS  = 10000;
const MAX_SUMMARY_CHARS  = 2000;
const MAX_TOKENS         = 1600;
const MAX_STRATEGY_CHARS = 2500;
const MAX_USER_PROMPT    = 15000;

const VALID_DOMAINS = new Set(['ci', 'regulatory', 'safety', 'bd']);
const VALID_IMPACTS = new Set(['HIGH', 'MED', 'LOW', 'UNSET']);
const VALID_TYPES   = new Set([
  'trial_update', 'regulatory', 'publication', 'conference',
  'safety', 'safety_signal', 'recall', 'label_update',
  'material_event', 'news', 'other',
]);
const VALID_OVERRIDES      = new Set(['UPGRADE', 'DOWNGRADE', 'DISMISS', 'REOPEN', 'RECLASSIFY', null]);
const VALID_ACTIONS        = new Set(['ESCALATE', 'MONITOR', 'DISMISS', 'REVIEW', 'EXPEDITE']);
const VALID_SEVERITIES     = new Set(['CRITICAL', 'SERIOUS', 'MODERATE', 'MINOR', 'UNKNOWN']);
const VALID_PATIENT_IMPACT = new Set(['WIDESPREAD', 'SIGNIFICANT', 'LIMITED', 'MINIMAL', 'UNKNOWN']);

const MODELS = {
  FLAGSHIP: 'openai/gpt-4.1',
  STANDARD: 'openai/gpt-4.1-mini',
  FAST:     'openai/gpt-4.1-nano',
};

// RAW_TEXT structural keys to extract intelligently (ordered by priority)
const RAW_TEXT_KEYS = [
  'abstract', 'summary', 'description', 'title', 'notes', 'body', 'text',
  'reason_for_recall', 'product_description', 'reactions', 'outcomes',
  'indication', 'narrative', 'clinical_details', 'safety_concern',
  'regulatory_basis', 'action_taken', 'recommendations', 'background',
  'efficacy', 'adverse_events', 'conclusion', 'methodology', 'results',
  'sponsor_comment', 'fda_comment', 'market_context', 'competitive_landscape',
];

// ═══════════════════════════════════════════════════════════════════════════════
// §1  UTILITY FUNCTIONS
// ═══════════════════════════════════════════════════════════════════════════════

const safe = (v, fb = '') => {
  if (v === null || v === undefined) return fb;
  return String(v)
    .replace(/[\u0000-\u001F\u007F-\u009F]/g, '')
    .replace(/\s+/g, ' ')
    .trim() || fb;
};

const safeUp  = (v, fb = 'UNKNOWN') => safe(v, fb).toUpperCase();
const safeLo  = (v, fb = 'unknown') => safe(v, fb).toLowerCase();
const numOr   = (v, fb = null)      => { const n = Number(v); return Number.isFinite(n) ? n : fb; };
const clamp   = (n, lo, hi)         => Math.max(lo, Math.min(hi, n));
const isoNow  = ()                  => new Date().toISOString();
const trunc   = (s, mx)             => s.length > mx ? s.slice(0, mx) + '\n...[truncated]' : s;
const coal    = (...a)              => { for (const v of a) { const s = safe(v); if (s) return s; } return ''; };
const isTrue  = (v)                 => v === true || v === 'true' || v === 1 || v === '1';
const roundF  = (n, d = 2)         => Number.isFinite(n) ? +n.toFixed(d) : null;

const parseJ = (v) => {
  if (v === null || v === undefined) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try { const p = JSON.parse(v); return typeof p === 'object' && !Array.isArray(p) ? p : {}; } catch (_) { return {}; }
};

const parseArr = (v) => {
  if (Array.isArray(v)) return v;
  try { const p = JSON.parse(v); return Array.isArray(p) ? p : []; } catch (_) { return []; }
};

const simpleHash = (str) => {
  let h = 0;
  for (let i = 0; i < str.length; i++) {
    h = ((h << 5) - h) + str.charCodeAt(i);
    h |= 0;
  }
  return Math.abs(h).toString(16).padStart(16, '0');
};

const fmtHours = (h) => {
  if (h === null || h === undefined || isNaN(h)) return 'unknown';
  if (h < 1)   return `${Math.round(h * 60)}m`;
  if (h < 24)  return `${roundF(h, 1)}h`;
  if (h < 168) return `${roundF(h / 24, 1)}d`;
  return `${roundF(h / 168, 1)}w`;
};

const dedupeArr = (arr) => [...new Set(arr.filter(Boolean).map(s => String(s).trim()))];

// ═══════════════════════════════════════════════════════════════════════════════
// §2  LOAD INPUT SIGNAL
// ═══════════════════════════════════════════════════════════════════════════════

const s = $input.item.json;
if (!s || typeof s !== 'object') {
  throw new Error('[PharmaOS:v5] Input item is null or non-object — check upstream node');
}

// ═══════════════════════════════════════════════════════════════════════════════
// §3  LOAD CONTEXT NODES (Asset Registry + Strategy Memory)
// ═══════════════════════════════════════════════════════════════════════════════

let assets = [];
try {
  const allItems = $('Merge Context').all();
  assets = allItems
    .map(i => i.json)
    .filter(a => a && (a.id || a.asset_id) && (a.name || a.drug_name));
} catch (_) { /* no asset registry — continue gracefully */ }

let memories = [];
try {
  const memItems = $('Fetch Strategy Memory').all();
  memories = memItems
    .map(i => i.json)
    .filter(m => m && m.decision_made && m.decision_type);
} catch (_) { /* no strategy memory — continue gracefully */ }

// ═══════════════════════════════════════════════════════════════════════════════
// §4  NORMALIZE ALL CORE FIELDS
// ═══════════════════════════════════════════════════════════════════════════════

// Identity
const signalId   = coal(s.source_id, String(s.id || '')) || null;
const domain     = VALID_DOMAINS.has(safeLo(s.signal_domain)) ? safeLo(s.signal_domain) : 'ci';
const signalType = (() => { const t = safeLo(coal(s.signal_type, 'other')); return VALID_TYPES.has(t) ? t : 'other'; })();
const source     = safe(s.source, 'unknown');
const title      = safe(s.title, 'NA');
const url        = safe(s.url, '');
const fingerprint = safe(s.fingerprint) || simpleHash(domain + '|' + safe(s.drug_name) + '|' + signalType + '|' + source);
const dedupHash   = safe(s.deduphash)   || simpleHash((signalId || '') + '|' + title);

// Drug / Asset
const drug       = safe(coal(s.drug_name, s.entity_name), 'Unknown');
const indication = safe(s.indication, 'Unknown');
const sponsor    = safe(s.sponsor, 'Unknown');
const phase      = safe(s.phase, 'NA');
const status     = safe(s.status, 'NA');
const moa        = safe(s.moa, '');
const modality   = safe(s.modality, '');
const geography  = safe(s.geography, '');
const nctId      = safe(s.nct_id, '');
const assetId    = safe(s.asset_id, '');

// Risk & Scoring
const prevLevel      = VALID_IMPACTS.has(safeUp(s.impact_level, 'UNSET')) ? safeUp(s.impact_level, 'UNSET') : 'UNSET';
const prevScore      = numOr(s.impact_score, null);
const priorityScore  = numOr(s.priority_score, null);
const qualityScore   = numOr(s.quality_score, null);
const notifPriority  = safe(s.notif_priority, 'P4');
const routeTier      = safe(s.route_tier, 'T4_LOG');
const prevSafetySev  = safe(s.safety_severity, '');
const prevPatientImp = safe(s.patient_impact_estimate, '');
const confidence     = safe(s.confidence, '');

// SQL-Computed Fields
const compositeScore    = numOr(s.composite_score, null);
const domainRank        = numOr(s.domain_rank, null);
const ageHours          = numOr(s.age_hours, null);
const ingestAgeHours    = numOr(s.ingest_age_hours, null);
const mergeAgeHours     = numOr(s.merge_age_hours, null);
const versionLag        = numOr(s.version_lag, 0);
const needsRetriage     = isTrue(s.needs_retriage);
const urgencyWeight     = numOr(s.urgency_weight, 0);
const tokenRatio        = numOr(s.completion_token_ratio, null);
const fieldCompleteness = numOr(s.field_completeness_score, null);
const aiReadiness       = safe(s.ai_readiness, 'PENDING');
const stalenessTier     = safe(s.staleness_tier, 'UNKNOWN');
const routingRec        = safe(s.routing_recommendation, 'MONITOR');
const mergeReady        = isTrue(s.merge_ready);
const dupRiskScore      = numOr(s.dup_risk_score, 0);

// Flags
const competitor   = isTrue(s.competitor_flag);
const isUrgent     = isTrue(s.is_urgent);
const aiProcessed  = isTrue(s.ai_processed);
const stratMemUsed = isTrue(s.strategymemoryused);

// Override & Governance
const overStat   = safe(s.override_status, '');
const overBy     = safe(s.override_by, '');
const overReason = safe(s.override_reason, '');

// Triage & Quality
const qualityDecision   = safe(s.qualitydecision, '');
const qualityFlags      = parseArr(s.qualityflags);
const contextQualityRaw = safe(s.contextquality, '');
const assetMatchMethod  = safe(s.assetmatchmethod, safe(s.matchmethod, 'none'));
const duplicateRisk     = safe(s.duplicaterisk, 'UNKNOWN');
const mergeStatus       = safe(s.merge_status, '');
const refusal           = safe(s.refusal, '');
const triageHints       = parseJ(s.triagehints);
const triageMeta        = parseJ(s._triage_meta);
const aiClassification  = parseJ(s.ai_classification);

// AI Metadata (previous run if re-triage)
const prevAiSummary    = safe(s.ai_summary, '');
const prevRecommended  = safe(s.recommended_action, '');
const modelUsed        = safe(s.modelused, '');
const promptTokens     = numOr(s.prompttokens, 0);
const completionTokens = numOr(s.completiontokens, 0);
const totalTokens      = numOr(s.totaltokens, 0);

// Pipeline
const version    = numOr(s.version, 1);
const scoringVer = numOr(s.scoring_version, 0);

// Timestamps
const ingestedAt  = s.ingested_at   || null;
const firstSeenAt = s.first_seen_at || null;
const lastSeenAt  = s.last_seen_at  || null;
const mergedAt    = s.mergeat       || null;

// ═══════════════════════════════════════════════════════════════════════════════
// §5  RICH CONTEXT EXTRACTION — raw_text + summary + structured fields
// ═══════════════════════════════════════════════════════════════════════════════

const extractContext = () => {
  const blocks = [];
  const seen   = new Set();

  const addBlock = (label, text) => {
    const cleaned = safe(text);
    if (!cleaned || cleaned.length < 10) return;
    const key = cleaned.slice(0, 80);
    if (seen.has(key)) return;
    seen.add(key);
    blocks.push(`[${label.toUpperCase()}]\n${cleaned}`);
  };

  // A. raw_text — richest primary source
  if (s.raw_text) {
    if (typeof s.raw_text === 'string') {
      const rt = s.raw_text.trim();
      try {
        const parsed = JSON.parse(rt);
        if (typeof parsed === 'object' && !Array.isArray(parsed)) {
          for (const k of RAW_TEXT_KEYS) {
            if (parsed[k]) addBlock(`raw.${k}`, parsed[k]);
          }
          // Remaining unknown keys
          const remaining = Object.entries(parsed)
            .filter(([k]) => !RAW_TEXT_KEYS.includes(k) && parsed[k])
            .map(([k, v]) => `${k}: ${typeof v === 'object' ? JSON.stringify(v) : v}`)
            .join('\n');
          if (remaining) addBlock('raw.additional_fields', remaining);
        } else {
          addBlock('raw_text', rt);
        }
      } catch (_) {
        addBlock('raw_text', trunc(rt, MAX_CONTEXT_CHARS));
      }
    } else if (typeof s.raw_text === 'object') {
      for (const k of RAW_TEXT_KEYS) {
        if (s.raw_text[k]) addBlock(`raw.${k}`, s.raw_text[k]);
      }
      for (const [k, v] of Object.entries(s.raw_text)) {
        if (!RAW_TEXT_KEYS.includes(k) && v) {
          addBlock(`raw.${k}`, typeof v === 'object' ? JSON.stringify(v) : String(v));
        }
      }
    }
  }

  // B. summary field
  if (s.summary) {
    addBlock('summary', trunc(safe(s.summary), MAX_SUMMARY_CHARS));
  }

  // C. Previous AI summary (from prior processing run)
  if (prevAiSummary) {
    addBlock('previous_ai_summary', trunc(prevAiSummary, 800));
  }

  // D. Structured signal fields as supplementary context
  const structuredLines = [];
  if (title !== 'NA')           structuredLines.push(`Title: ${title}`);
  if (drug !== 'Unknown')       structuredLines.push(`Drug/Entity: ${drug}`);
  if (indication !== 'Unknown') structuredLines.push(`Indication: ${indication}`);
  if (sponsor !== 'Unknown')    structuredLines.push(`Sponsor/Firm: ${sponsor}`);
  if (moa)                      structuredLines.push(`Mechanism of Action: ${moa}`);
  if (modality)                 structuredLines.push(`Modality: ${modality}`);
  if (phase !== 'NA')           structuredLines.push(`Trial Phase: ${phase}`);
  if (status !== 'NA')          structuredLines.push(`Status: ${status}`);
  if (geography)                structuredLines.push(`Geography: ${geography}`);
  if (nctId)                    structuredLines.push(`NCT ID: ${nctId}`);
  if (url)                      structuredLines.push(`Source URL: ${url}`);
  if (structuredLines.length > 0) addBlock('structured_signal_fields', structuredLines.join('\n'));

  // E. AI classification from previous run
  if (Object.keys(aiClassification).length > 0) {
    addBlock('prior_ai_classification', JSON.stringify(aiClassification, null, 2));
  }

  // F. Triage hints & meta
  const triageLines = [];
  if (Object.keys(triageHints).length > 0) triageLines.push(`Triage Hints: ${JSON.stringify(triageHints)}`);
  if (triageMeta.qualitytier)    triageLines.push(`Quality Tier: ${triageMeta.qualitytier}`);
  if (triageMeta.contextquality) triageLines.push(`Context Quality: ${triageMeta.contextquality}`);
  if (triageMeta.duplicaterisk)  triageLines.push(`Duplicate Risk: ${triageMeta.duplicaterisk}`);
  if (triageLines.length > 0)   addBlock('triage_operational_context', triageLines.join('\n'));

  const combined = blocks.join('\n\n─────────────────────────\n\n');
  return trunc(combined, MAX_CONTEXT_CHARS);
};

const combinedContext = extractContext();
const contextChars    = combinedContext.length;
const hasRichContext  = contextChars > 500;

// ═══════════════════════════════════════════════════════════════════════════════
// §6  ASSET MATCHING ENGINE (4-pass)
// ═══════════════════════════════════════════════════════════════════════════════

let matchedAssetId      = assetId || null;
let matchedAsset        = null;
let resolvedMatchMethod = assetMatchMethod || 'none';

if (!matchedAssetId && drug !== 'Unknown' && assets.length > 0) {
  const drugLo = drug.toLowerCase().trim();

  // Pass 1: Exact name
  for (const a of assets) {
    if ((a.name || a.drug_name || '').toLowerCase().trim() === drugLo) {
      matchedAssetId = a.id || a.asset_id;
      matchedAsset = a;
      resolvedMatchMethod = 'exact_name';
      break;
    }
  }

  // Pass 2: Alias exact
  if (!matchedAssetId) {
    for (const a of assets) {
      for (const alias of dedupeArr(parseArr(a.aliases))) {
        if (alias.toLowerCase().trim() === drugLo) {
          matchedAssetId = a.id || a.asset_id;
          matchedAsset = a;
          resolvedMatchMethod = 'alias_exact';
          break;
        }
      }
      if (matchedAssetId) break;
    }
  }

  // Pass 3: Fuzzy substring (min 4 chars)
  if (!matchedAssetId && drugLo.length >= 4) {
    for (const a of assets) {
      const nameLo = (a.name || a.drug_name || '').toLowerCase();
      if (nameLo.includes(drugLo) || drugLo.includes(nameLo)) {
        matchedAssetId = a.id || a.asset_id;
        matchedAsset = a;
        resolvedMatchMethod = 'fuzzy_name_substring';
        break;
      }
      for (const alias of dedupeArr(parseArr(a.aliases))) {
        const aLo = alias.toLowerCase();
        if (aLo.includes(drugLo) || drugLo.includes(aLo)) {
          matchedAssetId = a.id || a.asset_id;
          matchedAsset = a;
          resolvedMatchMethod = 'fuzzy_alias_substring';
          break;
        }
      }
      if (matchedAssetId) break;
    }
  }

  // Pass 4: Indication-based fallback
  if (!matchedAssetId && indication !== 'Unknown') {
    const indLo = indication.toLowerCase();
    for (const a of assets) {
      const aIndLo = (a.indication || a.primary_indication || '').toLowerCase();
      if (aIndLo && (aIndLo.includes(indLo) || indLo.includes(aIndLo))) {
        matchedAssetId = a.id || a.asset_id;
        matchedAsset = a;
        resolvedMatchMethod = 'indication_fallback';
        break;
      }
    }
  }

} else if (matchedAssetId && assets.length > 0) {
  matchedAsset = assets.find(a => (a.id || a.asset_id) === matchedAssetId) || null;
  resolvedMatchMethod = matchedAsset ? 'pre_linked' : 'pre_linked_unresolved';
}

const assetName             = matchedAsset ? safe(matchedAsset.name || matchedAsset.drug_name) : null;
const assetPriority         = matchedAsset ? safe(matchedAsset.strategic_priority, 'NORMAL') : null;
const assetCompetitiveSet   = matchedAsset ? dedupeArr(parseArr(matchedAsset.competitive_set)) : [];
const assetIndication       = matchedAsset ? safe(matchedAsset.indication || matchedAsset.primary_indication, '') : '';
const assetPhase            = matchedAsset ? safe(matchedAsset.phase, '') : '';
const assetTherapeuticArea  = matchedAsset ? safe(matchedAsset.therapeutic_area, '') : '';

// ═══════════════════════════════════════════════════════════════════════════════
// §7  STRATEGY MEMORY INJECTION
// ═══════════════════════════════════════════════════════════════════════════════

let strategyContext        = '';
let strategyMemoryUsedFlag = false;
let strategyMemoryCount    = 0;

if (memories.length > 0) {
  const drugLo    = drug.toLowerCase();
  const indicLo   = indication.toLowerCase();
  const sponsorLo = sponsor.toLowerCase();

  const relevant = memories
    .filter(m => {
      if (!m.decision_made) return false;
      const text = [m.question, m.decision_made, m.context || ''].join(' ').toLowerCase();
      if (matchedAssetId && (m.asset_id === matchedAssetId || m.asset_id === assetId)) return true;
      if (drug !== 'Unknown'       && text.includes(drugLo))    return true;
      if (indication !== 'Unknown' && text.includes(indicLo))   return true;
      if (sponsor !== 'Unknown'    && text.includes(sponsorLo)) return true;
      if (domain                   && text.includes(domain))    return true;
      return false;
    })
    .sort((a, b) => new Date(b.made_at || 0).getTime() - new Date(a.made_at || 0).getTime())
    .slice(0, 6);

  if (relevant.length > 0) {
    strategyMemoryCount    = relevant.length;
    strategyMemoryUsedFlag = true;
    strategyContext = relevant.map((m, i) => {
      const lines = [
        `[MEMORY ${i + 1}] Type: ${m.decision_type} | Made: ${m.made_at ? m.made_at.slice(0, 10) : 'unknown'} | By: ${m.made_by || 'system'}`,
        `Decision: ${m.decision_made}`,
      ];
      if (m.question)  lines.push(`Context: ${trunc(m.question, 200)}`);
      if (m.rationale) lines.push(`Rationale: ${trunc(m.rationale, 200)}`);
      return lines.join('\n');
    }).join('\n\n');
    strategyContext = trunc(strategyContext, MAX_STRATEGY_CHARS);
  }
}

// ═══════════════════════════════════════════════════════════════════════════════
// §8  QUALITY SCORING (10-factor expanded)
// ═══════════════════════════════════════════════════════════════════════════════

let qScore     = 0;
const qFlags   = [...qualityFlags];
const addFlag  = (f) => { if (!qFlags.includes(f)) qFlags.push(f); };

if (drug !== 'Unknown')           { qScore += 2;   } else { addFlag('missing_drug'); }
if (indication !== 'Unknown')     { qScore += 2;   } else { addFlag('missing_indication'); }
if (sponsor !== 'Unknown')        { qScore += 1;   } else { addFlag('missing_sponsor'); }
if (phase !== 'NA')               { qScore += 1;   } else { addFlag('missing_phase'); }
if (contextChars > 500)           { qScore += 2;   } else { addFlag('sparse_context'); }
if (url)                          { qScore += 1;   } else { addFlag('missing_url'); }
if (title !== 'NA')               { qScore += 0.5; } else { addFlag('missing_title'); }
if (matchedAssetId)               { qScore += 0.5; } else { addFlag('no_asset_match'); }
if (moa || modality)              { qScore += 0.5; } else { addFlag('missing_moa_modality'); }
if (prevAiSummary)                { qScore += 0.5; }       // prior AI run
if (duplicateRisk === 'HIGH')     { qScore -= 1;   addFlag('high_duplicate_risk'); }
if (refusal)                      { qScore -= 0.5; addFlag('prior_refusal'); }
if (versionLag > 2)               { qScore -= 0.5; addFlag('high_version_lag'); }

qScore = clamp(qScore, 0, 10);

const resolvedContextQuality = contextQualityRaw ||
  (qScore >= 8 ? 'RICH' : qScore >= 5 ? 'ADEQUATE' : qScore >= 3 ? 'SPARSE' : 'MINIMAL');

// ═══════════════════════════════════════════════════════════════════════════════
// §9  FINGERPRINTING
// ═══════════════════════════════════════════════════════════════════════════════

const computedFingerprint = fingerprint || simpleHash(domain + '|' + drug + '|' + signalType + '|' + source);
const computedDedupHash   = dedupHash   || simpleHash((signalId || '') + '|' + title);

// ═══════════════════════════════════════════════════════════════════════════════
// §10  MODEL ROUTING
// ═══════════════════════════════════════════════════════════════════════════════

let model, modelReason;

const isSafetyDomain     = domain === 'safety';
const isHighSeverity     = ['CRITICAL', 'SERIOUS'].includes(safeUp(prevSafetySev));
const isCompetitorUrgent = competitor && isUrgent;
const hasOverride        = overStat && !['', 'none'].includes(overStat.toLowerCase());
const isHighComposite    = compositeScore !== null && compositeScore >= 7.5;
const isRetriage         = needsRetriage && versionLag > 0;
const isFreshSignal      = stalenessTier === 'FRESH';

if (isSafetyDomain)                              { model = MODELS.FLAGSHIP; modelReason = 'safety_domain → always_flagship (patient safety override)'; }
else if (isHighSeverity && domain !== 'ci')      { model = MODELS.FLAGSHIP; modelReason = `high_severity(${prevSafetySev}) → flagship`; }
else if (isCompetitorUrgent)                     { model = MODELS.FLAGSHIP; modelReason = 'urgent_AND_competitor → flagship (dual-flag escalation)'; }
else if (isUrgent || competitor)                 { model = MODELS.FLAGSHIP; modelReason = `${isUrgent ? 'urgent' : 'competitor'}_flag → flagship`; }
else if (isHighComposite)                        { model = MODELS.FLAGSHIP; modelReason = `high_composite_score(${compositeScore}) → flagship`; }
else if (hasOverride)                            { model = MODELS.STANDARD; modelReason = `override_present(${overStat}) → standard`; }
else if (isRetriage)                             { model = MODELS.STANDARD; modelReason = `needs_retriage(lag=${versionLag}) → standard`; }
else if (domain === 'regulatory')                { model = MODELS.STANDARD; modelReason = 'regulatory_domain → standard'; }
else if (resolvedContextQuality === 'MINIMAL')   { model = MODELS.FAST;     modelReason = 'minimal_context → fast'; }
