let payload;
if (typeof content === 'string') {
  const cleaned = content.trim().replace(/^```json[\r\n]*/i,'').replace(/^```[\r\n]*/,'').replace(/```$/,'').trim();
  try { payload = JSON.parse(cleaned); }
  catch(e) { throw new Error('[PharmaOS:Merge] JSON parse failed: ' + e.message + ' | ' + cleaned.slice(0,400)); }
} else if (typeof content === 'object' && content !== null) {
  payload = content;
} else { throw new Error('[PharmaOS:Merge] Unexpected content type: ' + typeof content); }

// Helpers
const numOr = (v, fb) => { const n = Number(v); return Number.isFinite(n) ? n : fb; };
const clamp = (n, lo, hi) => Math.max(lo, Math.min(n, hi));
const VI = new Set(['HIGH','MED','LOW']);
const VA = new Set(['ESCALATE','MONITOR','DISMISS','REVIEW','EXPEDITE']);
const VT = new Set(['trial_update','regulatory','publication','conference','safety','safety_signal','recall','label_update','material_event','news','other']);
const safeI = v => { const u = String(v||'').toUpperCase(); return VI.has(u) ? u : 'LOW'; };
const safeA = v => { const u = String(v||'').toUpperCase(); return VA.has(u) ? u : 'MONITOR'; };
const safeT = v => { const l = String(v||'').toLowerCase(); return VT.has(l) ? l : 'other'; };

// Normalize
const impactLevel = safeI(payload.impact_level);
const impactScore = clamp(numOr(payload.impact_score, 0), 0, 10);
const signalType  = safeT(payload.signal_type);
const compFlag    = !!payload.competitor_flag;
const aiSummary   = String(payload.ai_summary || '').trim();
const recAction   = safeA(payload.recommended_action);
const scoreBreakdown = {
  drivers:    Array.isArray(payload.score_breakdown?.drivers) ? payload.score_breakdown.drivers.map(String) : [],
  risks:      Array.isArray(payload.score_breakdown?.risks)   ? payload.score_breakdown.risks.map(String)   : [],
  confidence: clamp(numOr(payload.score_breakdown?.confidence, 0.3), 0, 1)
};

// Safety-specific fields
const safetySeverity = payload.safety_severity || null;
const patientImpact  = payload.patient_impact_estimate || null;

const meta     = original._meta           || {};
const features = original.ai_features     || {};

const merged = {
  id:              original.id             || null,
  source_id:       original.source_id      || null,
  signal_domain:   features.signal_domain  || 'ci',
  source:          original.source         || null,
  title:           original.title          || null,
  drug_name:       original.drug_name      || features.drug        || null,
  entity_name:     original.entity_name    || null,
  indication:      original.indication     || features.indication  || null,
  sponsor:         original.sponsor        || features.sponsor     || null,
  phase:           original.phase          || features.trial_phase || null,
  status:          original.status         || features.trial_status|| null,
  moa:             original.moa            || features.moa         || null,
  modality:        original.modality       || features.modality    || null,
  geography:       original.geography      || features.geography   || null,
  nct_id:          original.nct_id         || features.nct_id      || null,
  url:             original.url            || features.url         || null,
  raw_text:        original.raw_text       || null,
  summary:         original.summary        || null,
  asset_id:        features.asset_id       || null,
  ingested_at:     original.ingested_at    || null,
  first_seen_at:   original.first_seen_at  || null,
  last_seen_at:    original.last_seen_at   || null,
  version:         original.version        ?? null,
  scoring_version: original.scoring_version?? null,
  override_status: original.override_status|| null,
  override_by:     original.override_by    || null,
  override_reason: original.override_reason|| null,
  is_urgent:       original.is_urgent      ?? false,
  priority_base:   original.priority_base  ?? null,
  age_hours:       original.age_hours      ?? null,

  // AI outputs
  competitor_flag:    compFlag,
  impact_level:       impactLevel,
  impact_score:       impactScore,
  signal_type:        signalType,
  ai_summary:         aiSummary,
  ai_classification:  { safety_severity: safetySeverity, patient_impact: patientImpact },
  recommended_action: recAction,
  score_breakdown:    scoreBreakdown,
  ai_processed:       true,
  confidence:         scoreBreakdown.confidence >= 0.75 ? 'high' : scoreBreakdown.confidence >= 0.45 ? 'medium' : 'low',
  refusal:            payload.refusal   ?? null,

  // Meta
  _triage_meta: {
    model_used:           httpRaw.model || meta.model_selected || null,
    model_routing_reason: meta.model_routing_reason || null,
    signal_domain:        features.signal_domain || 'ci',
    context_quality:      meta.context_quality || null,
    quality_score:        meta.quality_score ?? null,
    quality_flags:        meta.quality_flags || [],
    asset_id:             features.asset_id || null,
    asset_match_method:   meta.asset_match_method || null,
    strategy_memory_used: meta.strategy_memory_injected || false,
    fingerprint:          meta.fingerprint || null,
    dedup_hash:           meta.dedup_hash || null,
    pipeline_version:     meta.pipeline_version || '5.0.0',
    temperature_used:     meta.temperature ?? null,
    prompt_tokens:        httpRaw.usage?.prompt_tokens ?? null,
    completion_tokens:    httpRaw.usage?.completion_tokens ?? null,
    total_tokens:         httpRaw.usage?.total_tokens ?? null,
    merged_at:            new Date().toISOString(),
  }
};

return [{ json: merged }];

/**
 * PharmaOS WF2 — Restore + Route (Pre-Router)
 * Version: 5.0.0
 *
 * 1. Restore full signal after DB update
 * 2. 8-factor composite priority score (safety bias)
 * 3. 10-tier routing
 * 4. Compound event detection
 * 5. Alert channel assignment
 * 6. Override compliance
 * 7. Signal velocity
 * 8. Audit trail
 * 9. System health metrics
 */
'use strict';

const PIPELINE = '5.0.0';
const CRITICAL_THRESH = 9.0;
const HIGH_THRESH     = 7.0;
const MED_ELEV_THRESH = 5.5;
const URGENT_AGE_H    = 48;
const CONF_HIGH       = 0.75;
const CONF_ALERT      = 0.60;

const TIERS = {
  CRITICAL:'CRITICAL', HIGH_COMPETITOR:'HIGH_COMPETITOR', HIGH:'HIGH',
  SAFETY_ESCALATION:'SAFETY_ESCALATION', MED_ELEVATED:'MED_ELEVATED',
  MED:'MED', LOW:'LOW', DISMISS:'DISMISS', AI_FAILED:'AI_FAILED', DB_FAILED:'DB_FAILED'
};

const NOTIF = {
  CRITICAL:'P0', HIGH_COMPETITOR:'P1', HIGH:'P1', SAFETY_ESCALATION:'P0',
  MED_ELEVATED:'P2', MED:'P3', LOW:'P4', DISMISS:'P5', AI_FAILED:'P1', DB_FAILED:'P0'
};

const CHANNELS = {
  CRITICAL:          ['pharmaos-critical','pharmaos-executive','email_exec','pagerduty'],
  HIGH_COMPETITOR:   ['pharmaos-ci-team','pharmaos-medical-affairs','email_ci_team'],
  HIGH:              ['pharmaos-medical-affairs','pharmaos-ci-team'],
  SAFETY_ESCALATION: ['pharmaos-critical','pharmaos-safety','pharmaos-executive','email_safety','pagerduty'],
  MED_ELEVATED:      ['pharmaos-ci-team'],
  MED:               ['digest_daily'],
  LOW:               ['digest_weekly'],
  DISMISS:           ['archive'],
  AI_FAILED:         ['pharmaos-ops','pagerduty'],
  DB_FAILED:         ['pharmaos-ops','pagerduty','email_ops'],
};

const numOr = (v,fb) => { const n=Number(v); return Number.isFinite(n)?n:fb; };
const clamp = (n,lo,hi) => Math.max(lo,Math.min(n,hi));
const round2 = n => Math.round(n*100)/100;
const safeStr = (v,fb='') => (v==null?fb:String(v).trim()||fb);
const safeBool = v => v===true||v==='true'||v===1;
const isoNow = () => new Date().toISOString();
const hoursAgo = iso => { if(!iso) return null; const ms=Date.now()-new Date(iso).getTime(); return Number.isFinite(ms)?round2(ms/3600000):null; };

const updateResult = $input.item.json;
let full;
try { full = $('Merge AI Output').item.json; }
catch(e) { throw new Error('[PharmaOS:Restore] Cannot read Merge AI Output: '+e.message); }

// Normalize
const signalId    = safeStr(full.source_id||full.id, null);
const domain      = safeStr(full.signal_domain, 'ci');
const drug        = safeStr(full.drug_name||full.entity_name, 'Unknown');
const indication  = safeStr(full.indication, 'Unknown');
const sponsor     = safeStr(full.sponsor, 'Unknown');
const phase       = safeStr(full.phase, 'NA');
const trialStatus = safeStr(full.status, 'NA');
const title       = safeStr(full.title, 'NA');
const source      = safeStr(full.source, 'unknown');
const url         = safeStr(full.url, '');

const impactLevel = safeStr(full.impact_level, 'LOW').toUpperCase();
const impactScore = clamp(numOr(full.impact_score,0),0,10);
const signalType  = safeStr(full.signal_type, 'other').toLowerCase();
const recAction   = safeStr(full.recommended_action, 'MONITOR').toUpperCase();
const overStat    = safeStr(full.override_status, '');
const overBy      = safeStr(full.override_by, '');
const isUrgent    = safeBool(full.is_urgent);
const competitor  = safeBool(full.competitor_flag);
const aiProcessed = safeBool(full.ai_processed);
const dbSuccess   = !!(updateResult && updateResult.id);
const confidence  = clamp(numOr(full.score_breakdown?.confidence,0),0,1);
const drivers     = Array.isArray(full.score_breakdown?.drivers)?full.score_breakdown.drivers:[];
const risks       = Array.isArray(full.score_breakdown?.risks)?full.score_breakdown.risks:[];
const version     = numOr(full.version,1);
const firstSeenAt = full.first_seen_at||null;
const lastSeenAt  = full.last_seen_at||null;
const computedAge = hoursAgo(firstSeenAt)||numOr(full.age_hours,0);

// Safety-specific
const safetySeverity = full.ai_classification?.safety_severity || null;
const patientImpact  = full.ai_classification?.patient_impact || null;

// 8-FACTOR COMPOSITE PRIORITY SCORE
let pScore = impactScore;
if (competitor) pScore += 2.0;
if (isUrgent)   pScore += 2.0;
if (domain === 'safety') pScore += 1.0; // safety domain bias
if (['UPGRADE','REOPEN'].includes(overStat.toUpperCase())) pScore += 1.5;
if (overStat.toUpperCase() === 'DOWNGRADE') pScore -= 2.0;
if (computedAge < URGENT_AGE_H) pScore += 1.0;
if (confidence >= CONF_HIGH) pScore += 0.75;
else if (confidence >= CONF_ALERT) pScore += 0.5;
// Safety severity boost
if (safetySeverity === 'CRITICAL') pScore += 1.5;
else if (safetySeverity === 'SERIOUS') pScore += 0.75;
pScore = clamp(round2(pScore), 0, 10);

// 10-TIER ROUTING
let routeTier;
if (!dbSuccess && !aiProcessed) routeTier = TIERS.DB_FAILED;
else if (!aiProcessed) routeTier = TIERS.AI_FAILED;
else if (domain === 'safety' && (safetySeverity === 'CRITICAL' || impactLevel === 'HIGH'))
  routeTier = TIERS.SAFETY_ESCALATION;
else if (pScore >= CRITICAL_THRESH || (isUrgent && impactLevel === 'HIGH' && competitor))
  routeTier = TIERS.CRITICAL;
else if (impactLevel === 'HIGH' && competitor) routeTier = TIERS.HIGH_COMPETITOR;
else if (impactLevel === 'HIGH' || pScore >= HIGH_THRESH) routeTier = TIERS.HIGH;
else if (impactLevel === 'MED' && (isUrgent || competitor || pScore >= MED_ELEV_THRESH))
  routeTier = TIERS.MED_ELEVATED;
else if (impactLevel === 'MED') routeTier = TIERS.MED;
else if (recAction === 'DISMISS') routeTier = TIERS.DISMISS;
else routeTier = TIERS.LOW;

// ALERT CHANNELS
const channels = [...(CHANNELS[routeTier]||[])];
if (isUrgent && !channels.includes('pharmaos-executive')) channels.unshift('pharmaos-executive');
const uniqueChannels = [...new Set(channels)];

// OVERRIDE COMPLIANCE
let overViolation = false, overViolationReason = null;
if (['UPGRADE','REOPEN'].includes(overStat.toUpperCase()) && ['LOW','DISMISS'].includes(routeTier)) {
  overViolation = true;
  overViolationReason = `Signal was ${overStat} by ${overBy||'analyst'} but routed to ${routeTier}. Manual review required.`;
}
if (overStat.toUpperCase() === 'DOWNGRADE' && ['CRITICAL','SAFETY_ESCALATION'].includes(routeTier)) {
  overViolation = true;
  overViolationReason = `Signal was downgraded but AI scored ${routeTier} (score: ${pScore}). Flagged for review.`;
}

// SIGNAL VELOCITY
let velocity = null, velocityLabel = 'STABLE';
if (firstSeenAt && version > 1) {
  const span = hoursAgo(firstSeenAt) || 1;
  velocity = round2((version - 1) / span);
  velocityLabel = velocity >= 1.0 ? 'FAST' : velocity >= 0.25 ? 'ACTIVE' : velocity >= 0.05 ? 'SLOW' : 'STABLE';
}

// AUDIT
const audit = {
  event: 'SIGNAL_ROUTED', pipeline_version: PIPELINE,
  signal_id: signalId, signal_domain: domain, route_tier: routeTier,
  notif_priority: NOTIF[routeTier]||'P4', priority_score: pScore,
  impact_level: impactLevel, impact_score: impactScore, confidence,
  competitor_flag: competitor, is_urgent: isUrgent,
  override_status: overStat, override_violation: overViolation,
  safety_severity: safetySeverity, patient_impact: patientImpact,
  velocity_label: velocityLabel, timestamp: isoNow(),
};

// SYSTEM HEALTH METRICS (to be written by next node)
const healthMetrics = [
  { metric_name: 'wf2_signal_processed', metric_value: 1, metric_unit: 'count', tags: { domain, route_tier: routeTier } },
  { metric_name: 'wf2_impact_score', metric_value: impactScore, metric_unit: 'score', tags: { domain, signal_id: signalId } },
  { metric_name: 'wf2_priority_score', metric_value: pScore, metric_unit: 'score', tags: { domain, route_tier: routeTier } },
  { metric_name: 'wf2_confidence', metric_value: confidence, metric_unit: 'ratio', tags: { domain } },
  { metric_name: 'wf2_ai_tokens', metric_value: numOr(full._triage_meta?.total_tokens, 0), metric_unit: 'count', tags: { model: full._triage_meta?.model_used || 'unknown' } },
];

const enriched = {
  ...full,
  route_tier: routeTier,
  priority_score: pScore,
  notif_priority: NOTIF[routeTier]||'P4',
  alert_channels: uniqueChannels,
  override_violation: overViolation,
  override_violation_reason: overViolationReason,
  signal_velocity: velocity,
  velocity_label: velocityLabel,
  db_success: dbSuccess,
  _audit: audit,
  _health_metrics: healthMetrics,
  _routing_meta: {
    pipeline_version: PIPELINE, route_tier: routeTier,
    priority_score: pScore, notif_priority: NOTIF[routeTier]||'P4',
    alert_channels: uniqueChannels, safety_severity: safetySeverity,
    patient_impact: patientImpact, velocity_label: velocityLabel,
    routed_at: isoNow(),
  }
};

return [{ json: enriched }];

/**
 * PharmaOS WF2 — Process Compound Events
 * Input: output of "Compound Event Prep" (already scored/aggregated)
 * Output: enriched signal for downstream routing/alerts
 */

'use strict';

// Compound event summary from previous node
const compound = $input.first().json;

// Original routed signal from "Restore and Route"
let original;
try {
  original = $('Restore and Route').first().json;
} catch (e) {
  original = {};
}

// Helpers
const safeStr  = (v, fb = '') => v == null ? fb : String(v).trim() || fb;
const clamp10  = n => Math.min(10, Math.max(0, Number(n) || 0));
const isoNow   = () => new Date().toISOString();

// Basic anchor information
const drug       = safeStr(original.drug_name || original.entity_name, 'Unknown');
const indication = safeStr(original.indication, 'Unknown');
const domain     = safeStr(original.signal_domain, 'ci');

const events = {
  triple_threats:         compound.triple_threats         || [],
  recall_cascades:        compound.recall_cascades        || [],
  competitive_surges:     compound.competitive_surges     || [],
  ghost_clusters:         compound.ghost_clusters         || [],
  pipeline_accelerations: compound.pipeline_accelerations || [],
};

// Build compound_events records (to later persist into compound_events table)
const compoundEvents = [];

// TRIPLE_THREAT
for (const t of events.triple_threats) {
  const label = (t.drug_names && t.drug_names.length)
    ? t.drug_names.join('/')
    : t.entity_key || 'Unknown';

  const riskScore = clamp10(
    (t.peak_impact || 0) +
    (t.domain_count || 0) * 0.8 +
    (t.total_signals || 0) * 0.2
  );

  compoundEvents.push({
    title: `TRIPLE_THREAT [${t.match_confidence}] — ${label} across ${t.domain_count} domains`,
    domains: t.domains || [],
    trigger_pattern: 'ASSET_TRIPLE_THREAT',
    compound_risk_score: riskScore,
    pattern_metadata: t,
    escalation_level: t.domain_count >= 4 ? 'EXECUTIVE' : 'SENIOR',
    recommended_actions: [
      'Run cross-domain deep dive for this entity',
      'Prepare CI briefing for portfolio lead',
      'Validate asset / drug mapping correctness',
    ],
  });
}

// RECALL_CASCADE
for (const r of events.recall_cascades) {
  const riskScore = r.severity === 'CRITICAL'
    ? 10
    : r.severity === 'HIGH'
    ? 8
    : 6;

  compoundEvents.push({
    title: `RECALL_SAFETY_CASCADE [${r.severity}] — ${r.affected_entity} (${(r.safety_types || []).join(' + ')})`,
    domains: ['safety', 'regulatory'],
    trigger_pattern: 'RECALL_SAFETY_CASCADE',
    compound_risk_score: riskScore,
    pattern_metadata: r,
    escalation_level: r.severity === 'CRITICAL' ? 'EXECUTIVE' : 'SENIOR',
    recommended_actions: [
      'Immediate safety & regulatory triage',
      `Review ${r.total_safety_signals} safety/recall signals in last ${Math.round(r.cascade_hours || 0)}h`,
      'Prepare risk assessment for safety board',
    ],
  });
}

// COMPETITIVE_SURGE
for (const c of events.competitive_surges) {
  const riskScore = clamp10(
    (c.hit_count || 0) * 0.5 +
    (c.avg_impact || 0) * 0.3 +
    (c.competitor_count || 0) * 0.2
  );

  compoundEvents.push({
    title: `COMPETITIVE_SURGE [${c.intensity}] — ${c.hit_count} competitor signals in "${c.indication}"`,
    domains: c.domains || ['ci'],
    trigger_pattern: 'COMPETITIVE_SURGE',
    compound_risk_score: riskScore,
    pattern_metadata: c,
    escalation_level: c.intensity === 'SURGE' ? 'SENIOR' : 'STANDARD',
    recommended_actions: [
      `Track competitors: ${(c.competitors || []).slice(0, 5).join(', ')}`,
      'Update indication battlefield view',
      'Include in weekly CI / portfolio review',
    ],
  });
}

// GHOST_CLUSTER
for (const g of events.ghost_clusters) {
  const riskScore = clamp10(
    (g.avg_impact || 0) +
    (g.urgent_count || 0) * 0.7 +
    (g.cluster_size || 0) * 0.3
  );

  compoundEvents.push({
    title: `GHOST_CLUSTER — ${g.cluster_size} high-impact unidentified [${g.signal_type}] in [${g.signal_domain}]`,
    domains: [g.signal_domain],
    trigger_pattern: 'GHOST_CLUSTER',
    compound_risk_score: riskScore,
    pattern_metadata: g,
    escalation_level: g.urgent_count > 0 ? 'SENIOR' : 'STANDARD',
    recommended_actions: [
      'Run manual entity enrichment on cluster',
      'Investigate missing identifiers in ingestion pipeline',
      'Feed back into asset-matching model training',
    ],
  });
}

// PIPELINE_ACCELERATION
for (const p of events.pipeline_accelerations) {
  const riskScore = clamp10(
    (p.peak_impact || 0) * 0.4 +
    (p.trial_count || 0) * 0.4 +
    (p.signal_count || 0) * 0.2
  );

  compoundEvents.push({
    title: `PIPELINE_ACCELERATION — ${p.pipeline_entity} (${p.signal_count} signals, ${p.trial_count} trials)`,
    domains: ['ct_gov', 'regulatory'],
    trigger_pattern: 'PIPELINE_ACCELERATION',
    compound_risk_score: riskScore,
    pattern_metadata: p,
    escalation_level: riskScore >= 7 ? 'SENIOR' : 'STANDARD',
    recommended_actions: [
      'Update internal pipeline tracker',
      'Re-estimate launch/filing timelines',
      'Assess portfolio cannibalization / synergy',
    ],
  });
}

// Decide if we override routing based on compound events
const enriched = {
  ...original,
  compound_events_detected: compoundEvents,
  has_compound_event: compoundEvents.length > 0,
  compound_alert_score: compound.alert_score,
  compound_escalation_level: compound.escalation_level,
  compound_run_id: compound.run_id,
  compound_total_events: compound.total_events,
  compound_processed_at: isoNow(),
};

// Upgrade routing tier if necessary
if (compoundEvents.length > 0) {
  const hasExec = compoundEvents.some(e => e.escalation_level === 'EXECUTIVE');
  const hasSenior = compoundEvents.some(e => e.escalation_level === 'SENIOR');

  if (hasExec) {
    enriched.route_tier = 'CRITICAL';
    enriched.notif_priority = 'P0';
    enriched.alert_channels = Array.from(new Set([
      ...(original.alert_channels || []),
      'pharmaos-critical',
      'pharmaos-executive',
      'pharmaos-safety',
      'email_exec',
      'pagerduty',
    ]));
  } else if (hasSenior && (original.route_tier || '') !== 'CRITICAL') {
    enriched.route_tier = 'HIGH';
    enriched.notif_priority = 'P1';
    enriched.alert_channels = Array.from(new Set([
      ...(original.alert_channels || []),
      'pharmaos-ci-team',
      'pharmaos-medical-affairs',
    ]));
  }
}

return [{ json: enriched }];

'use strict';

const payload = $input.first().json || {};

const arr = (v) => Array.isArray(v) ? v : [];
const num = (v, fb = 0) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : fb;
};
const round2 = (n) => Math.round((num(n, 0) + Number.EPSILON) * 100) / 100;
const clamp = (n, lo, hi) => Math.max(lo, Math.min(hi, num(n, lo)));
const clamp10 = (n) => clamp(n, 0, 10);
const clamp01 = (n) => clamp(n, 0, 1);
const safe = (v, fb = '') => v == null ? fb : (String(v).trim() || fb);
const low = (v) => safe(v).toLowerCase();
const up = (v) => safe(v).toUpperCase();
const bool = (v) => v === true || v === 'true' || v === 1 || v === '1';
const uniq = (v) => [...new Set(arr(v).filter(x => x !== null && x !== undefined && String(x).trim() !== ''))];
const nowIso = () => new Date().toISOString();

const routeRank = {
  DISMISS: 0,
  LOW: 1,
  MED: 2,
  MED_ELEVATED: 3,
  HIGH: 4,
  HIGH_COMPETITOR: 5,
  SAFETY_ESCALATION: 6,
  CRITICAL: 7,
  AI_FAILED: -1,
  DB_FAILED: -1,
};

const routePriority = {
  CRITICAL: 'P0',
  SAFETY_ESCALATION: 'P0',
  HIGH_COMPETITOR: 'P1',
  HIGH: 'P1',
  MED_ELEVATED: 'P2',
  MED: 'P3',
  LOW: 'P4',
  DISMISS: 'P5',
};

const routeChannels = {
  CRITICAL: ['pharmaos-critical', 'pharmaos-executive', 'email_exec', 'pagerduty'],
  SAFETY_ESCALATION: ['pharmaos-critical', 'pharmaos-safety', 'pharmaos-executive', 'email_safety', 'pagerduty'],
  HIGH_COMPETITOR: ['pharmaos-ci-team', 'pharmaos-medical-affairs', 'email_ci_team'],
  HIGH: ['pharmaos-medical-affairs', 'pharmaos-ci-team'],
  MED_ELEVATED: ['pharmaos-ci-team'],
  MED: ['digest_daily'],
  LOW: ['digest_weekly'],
  DISMISS: ['archive'],
};

const escalationRank = {
  MONITOR: 0,
  STANDARD: 1,
  SENIOR: 2,
  EXECUTIVE: 3,
};

const strongerRoute = (a, b) => {
  const ra = routeRank[up(a)] ?? 0;
  const rb = routeRank[up(b)] ?? 0;
  return rb > ra ? up(b) : up(a);
};

const confidenceBandScore = (v) => {
  const x = low(v);
  if (x === 'high') return 8.5;
  if (x === 'medium') return 6.0;
  if (x === 'low') return 3.5;
  const n = Number(v);
  return Number.isFinite(n) ? clamp10(n <= 1 ? n * 10 : n) : 4.5;
};

const sourceSignal = (() => {
  if (payload.source_signal && typeof payload.source_signal === 'object') return payload.source_signal;
  if (payload.original_signal && typeof payload.original_signal === 'object') return payload.original_signal;
  return {};
})();

const dbResult = (() => {
  const x = payload.compound_db_result || {};
  return {
    triple_threats: arr(x.triple_threats || payload.triple_threats || payload.triplethreats),
    recall_cascades: arr(x.recall_cascades || payload.recall_cascades || payload.recallcascades),
    competitive_surges: arr(x.competitive_surges || payload.competitive_surges || payload.competitivesurges),
    ghost_clusters: arr(x.ghost_clusters || payload.ghost_clusters || payload.ghostclusters),
    pipeline_accelerations: arr(x.pipeline_accelerations || payload.pipeline_accelerations || payload.pipelineaccelerations),
    total_compound_events: num(x.total_compound_events || payload.total_compound_events || payload.totalcompoundevents, 0),
  };
})();

let events = arr(payload.compound_events_detected).map((e, idx) => {
  const risk = clamp10(e.compound_risk_score ?? e.risk_score ?? 0);
  const confRaw = e.confidence_score ?? e.confidence ?? 0.5;
  const conf = clamp01(Number(confRaw) > 1 ? Number(confRaw) / 10 : Number(confRaw));
  const urgency = clamp10(e.urgency_score ?? risk * 0.7);
  const evidence = clamp10(e.evidence_strength ?? risk * 0.75);
  const strategic = clamp10(e.strategic_relevance ?? risk * 0.70);
  const executive = clamp10(e.executive_score ?? risk * 0.72);
  const escalation = up(e.escalation_level || 'STANDARD');

  const attention =
    round2(
      risk * 0.34 +
      (conf * 10) * 0.12 +
      urgency * 0.16 +
      evidence * 0.14 +
      strategic * 0.14 +
      executive * 0.10
    );

  return {
    event_id: e.event_id || `CEV_${idx + 1}_${Date.now()}`,
    event_type: up(e.event_type || 'UNKNOWN'),
    title: safe(e.title, `Compound event ${idx + 1}`),
    trigger_pattern: safe(e.trigger_pattern, up(e.event_type || 'UNKNOWN')),
    domains: uniq(e.domains || []),
    escalation_level: escalation,
    compound_risk_score: round2(risk),
    confidence_score: round2(conf),
    urgency_score: round2(urgency),
    evidence_strength: round2(evidence),
    strategic_relevance: round2(strategic),
    executive_score: round2(executive),
    attention_score: round2(attention),
    risk_drivers: uniq(e.risk_drivers || []),
    caveats: uniq(e.caveats || []),
