const source = {
  route_tier: up(sourceSignal.route_tier || 'LOW'),
  notif_priority: safe(sourceSignal.notif_priority, 'P4'),
  alert_channels: uniq(sourceSignal.alert_channels || []),
  priority_score: num(sourceSignal.priority_score, num(sourceSignal.impact_score, 0)),
  impact_score: num(sourceSignal.impact_score, 0),
  impact_level: up(sourceSignal.impact_level || 'LOW'),
  signal_domain: low(sourceSignal.signal_domain || 'ci'),
  signal_type: low(sourceSignal.signal_type || 'other'),
  is_urgent: bool(sourceSignal.is_urgent),
  competitor_flag: bool(sourceSignal.competitor_flag),
  confidence_score: confidenceBandScore(sourceSignal.confidence),
  quality_score: num(sourceSignal.quality_score || sourceSignal._triage_meta?.quality_score, 5),
  override_status: up(sourceSignal.override_status || ''),
