events = events.map((e) => {
  const domainFit =
    e.domains.includes(source.signal_domain) ? 1.2 :
    (e.domains.includes('safety') && source.signal_domain === 'regulatory') ? 0.9 :
    (e.domains.includes('regulatory') && source.signal_domain === 'safety') ? 0.9 :
    0.3;

  const urgencyLift = source.is_urgent ? 0.8 : 0.1;
  const competitorLift = source.competitor_flag && ['COMPETITIVE_SURGE', 'TRIPLE_THREAT', 'PIPELINE_ACCELERATION'].includes(e.event_type) ? 0.9 : 0;
  const sourcePriorityLift = Math.min(source.priority_score, 10) * 0.08;
  const qualityPenalty = source.quality_score < 4 ? 0.5 : 0;

  const localRelevance = round2(clamp10(
    e.compound_risk_score * 0.42 +
    e.strategic_relevance * 0.22 +
    e.evidence_strength * 0.12 +
    e.urgency_score * 0.10 +
    domainFit +
    urgencyLift +
    competitorLift +
    sourcePriorityLift -
    qualityPenalty
  ));

  return {
    ...e,
    local_relevance_score: localRelevance,
    governing_score: round2(clamp10(
      e.attention_score * 0.45 +
      e.compound_risk_score * 0.25 +
      e.executive_score * 0.15 +
      localRelevance * 0.15
    ))
  };
});

