      (eventTypeCounts.GHOST_CLUSTER ? 0.8 : 0)
    )
  )
);

const derivedAlertScore = round2(
  events.reduce((sum, e) => {
    const w = {
      TRIPLE_THREAT: 8,
      RECALL_CASCADE: 10,
      COMPETITIVE_SURGE: 6,
      GHOST_CLUSTER: 4,
      PIPELINE_ACCELERATION: 5
    }[e.event_type] || 4;
    return sum + (num(e.compound_risk_score, 0) * w) + (num(e.local_relevance_score, 0) * 1.8);
  }, 0) + synergyBoost * 4.5
);

const compoundAlertScore = round2(Math.max(num(payload.compound_alert_score || payload.alert_score, 0), derivedAlertScore));

