const isoNow = () => new Date().toISOString();
const sf = (v, fb='N/A') => (v==null||v==='')?fb:String(v);

const signalId    = sf(s.source_id||s.id);
const domain      = sf(s.signal_domain, 'ci').toUpperCase();
const drug        = sf(s.drug_name||s.entity_name);
const indication  = sf(s.indication);
const sponsor     = sf(s.sponsor);
const phase       = sf(s.phase);
const status      = sf(s.status);
const impactLevel = sf(s.impact_level);
const impactScore = s.impact_score ?? 'N/A';
const routeTier   = sf(s.route_tier);
const pScore      = s.priority_score ?? 'N/A';
const notifP      = sf(s.notif_priority, 'P0');
const conf        = s.score_breakdown?.confidence;
const confStr     = typeof conf === 'number' ? (conf*100).toFixed(0)+'%' : 'N/A';
const aiSummary   = sf(s.ai_summary);
const recAction   = sf(s.recommended_action);
const signalType  = sf(s.signal_type);
const comp        = !!s.competitor_flag;
const urgent      = !!s.is_urgent;
const overStat    = sf(s.override_status, 'none');
const overBy      = sf(s.override_by, '');
const velLabel    = sf(s.velocity_label, 'STABLE');
const url         = sf(s.url, '');
const safSev      = sf(s.ai_classification?.safety_severity, '');
const patImp      = sf(s.ai_classification?.patient_impact, '');
const channels    = Array.isArray(s.alert_channels) ? s.alert_channels.join(', ') : 'N/A';

const drivers = Array.isArray(s.score_breakdown?.drivers)
  ? s.score_breakdown.drivers.slice(0,5).map(d=>'• '+d).join('\n') : 'N/A';
const risks = Array.isArray(s.score_breakdown?.risks)
  ? s.score_breakdown.risks.slice(0,4).map(r=>'⚠ '+r).join('\n') : 'N/A';

const tierEmoji = {
  CRITICAL:'🚨', SAFETY_ESCALATION:'☣️', HIGH_COMPETITOR:'🏁', HIGH:'🔴',
  MED_ELEVATED:'🟠', MED:'🟡', LOW:'🟢', DISMISS:'⚪', AI_FAILED:'💀', DB_FAILED:'💾'
};

const emoji = tierEmoji[routeTier] || '📊';
const compoundBlock = s.has_compound_event
  ? '\n\n🔥 *COMPOUND EVENT DETECTED:* ' + (s.compound_events_detected||[]).map(e=>e.title).join('; ')
  : '';

const slackBlocks = [
  { type:'header', text:{ type:'plain_text', text:`${emoji} [${notifP}] ${domain} Signal — ${drug}`, emoji:true }},
  { type:'divider' },
  { type:'section', fields:[
    {type:'mrkdwn',text:`*Drug:*\n${drug}`}, {type:'mrkdwn',text:`*Indication:*\n${indication}`},
    {type:'mrkdwn',text:`*Sponsor:*\n${sponsor}`}, {type:'mrkdwn',text:`*Domain:*\n${domain}`},
    {type:'mrkdwn',text:`*Phase:*\n${phase}`}, {type:'mrkdwn',text:`*Signal Type:*\n${signalType}`}
  ]},
  { type:'divider' },
  { type:'section', fields:[
    {type:'mrkdwn',text:`*Impact:*\n${impactLevel} (${impactScore}/10)`},
    {type:'mrkdwn',text:`*Priority:*\n${pScore}/10`},
    {type:'mrkdwn',text:`*Confidence:*\n${confStr}`},
    {type:'mrkdwn',text:`*Competitor:*\n${comp?'✅ YES':'❌ NO'}`},
    {type:'mrkdwn',text:`*Urgent:*\n${urgent?'⚡ YES':'NO'}`},
    {type:'mrkdwn',text:`*Velocity:*\n${velLabel}`}
  ]},
  ...(safSev ? [{ type:'section', fields:[
    {type:'mrkdwn',text:`*Safety Severity:*\n${safSev}`},
    {type:'mrkdwn',text:`*Patient Impact:*\n${patImp}`}
  ]}] : []),
  { type:'divider' },
  { type:'section', text:{type:'mrkdwn', text:`*AI Summary:*\n${aiSummary}${compoundBlock}`}},
  { type:'section', fields:[
    {type:'mrkdwn',text:`*Drivers:*\n${drivers}`},
    {type:'mrkdwn',text:`*Risks:*\n${risks}`}
  ]},
  { type:'divider' },
  { type:'section', fields:[
    {type:'mrkdwn',text:`*Action:*\n🔴 ${recAction}`},
    {type:'mrkdwn',text:`*Route Tier:*\n${routeTier}`},
    {type:'mrkdwn',text:`*Override:*\n${overStat.toUpperCase()}`},
    {type:'mrkdwn',text:`*Channels:*\n${channels}`}
  ]},
  ...(url?[{type:'actions',elements:[{type:'button',text:{type:'plain_text',text:'🔗 View Source',emoji:true},url,style:'primary'}]}]:[]),
  { type:'divider' },
  { type:'context', elements:[{type:'mrkdwn',text:`PharmaOS WF2 v5.0.0 • ${domain} • Signal: ${signalId} • ${isoNow()}`}]}
];

const emailSubject = `[${notifP}] ${emoji} ${domain} Signal: ${drug} — ${indication}`;
const emailBody = `${domain} INTELLIGENCE SIGNAL\n${'='.repeat(40)}\nPriority: ${notifP} | Tier: ${routeTier}\nSignal ID: ${signalId}\n\nDrug: ${drug} | Indication: ${indication}\nSponsor: ${sponsor} | Phase: ${phase}\nType: ${signalType} | Status: ${status}\n\nImpact: ${impactLevel} (${impactScore}/10) | Priority: ${pScore}/10\nConfidence: ${confStr} | Competitor: ${comp?'YES':'NO'}\nVelocity: ${velLabel}${safSev?'\nSafety Severity: '+safSev+' | Patient Impact: '+patImp:''}\n\nAI SUMMARY:\n${aiSummary}\n\nDRIVERS:\n${drivers}\n\nRISKS:\n${risks}\n\nACTION: ${recAction}\n\nURL: ${url||'N/A'}\n\nPharmaOS WF2 v5.0.0`;

const auditRow = {
  signal_id: signalId, signal_domain: domain.toLowerCase(),
  route_tier: routeTier, notif_priority: notifP,
  impact_level: impactLevel, impact_score: s.impact_score??null,
  priority_score: s.priority_score??null,
  confidence: typeof conf==='number'?conf:null,
  competitor_flag: comp, is_urgent: urgent,
  override_status: overStat, override_violation: !!s.override_violation,
  recommended_action: recAction, signal_type: signalType,
  alert_channels: JSON.stringify(s.alert_channels||[]),
  velocity_label: velLabel, ai_summary: aiSummary,
  safety_severity: safSev||null, patient_impact: patImp||null,
  routed_at: isoNow(), pipeline_version: '5.0.0',
};

return [{ json: { ...s, _alert: { slack_blocks: slackBlocks, email_subject: emailSubject, email_body: emailBody, audit_row: auditRow, formatted_at: isoNow() }}}];

