'use strict';

const prep = (() => {
  try { return $input.first().json || {}; } catch (_) { return {}; }
})();

const sourceSignal = (() => {
  if (prep && prep.source_signal && typeof prep.source_signal === 'object') return prep.source_signal;
  try { return $('Restore and Route').first().json || {}; } catch (_) { return {}; }
})();

const nowIso = () => new Date().toISOString();
const num = (v, fb = 0) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : fb;
};
const round2 = (n) => Math.round((num(n, 0) + Number.EPSILON) * 100) / 100;
const clamp = (n, lo, hi) => Math.max(lo, Math.min(hi, num(n, lo)));
const clamp10 = (n) => clamp(n, 0, 10);
const clamp01 = (n) => clamp(n, 0, 1);
const arr = (v) => Array.isArray(v) ? v : [];
const safe = (v, fb = '') => v == null ? fb : (String(v).trim() || fb);
const low = (v) => safe(v).toLowerCase();
const bool = (v) => v === true || v === 'true' || v === 1 || v === '1';
const uniq = (a) => [...new Set(arr(a).filter(x => x !== null && x !== undefined && String(x).trim() !== ''))];

const hoursAgo = (iso) => {
  if (!iso) return null;
  const t = new Date(iso).getTime();
  if (!Number.isFinite(t)) return null;
  return (Date.now() - t) / 3600000;
};

const recencyScore = (iso, horizonH = 72) => {
  const h = hoursAgo(iso);
  if (h == null) return 4.5;
  const scaled = 10 * (1 - Math.min(h, horizonH) / horizonH);
  return round2(clamp10(scaled));
};

const confidenceBandScore = (v) => {
  const x = low(v);
  if (x === 'high') return 8.5;
  if (x === 'medium') return 6.0;
  if (x === 'low') return 3.5;
  return 4.5;
};

const severityScore = (v) => {
  const x = safe(v).toUpperCase();
  if (x === 'CRITICAL') return 10;
  if (x === 'HIGH' || x === 'SERIOUS') return 8.5;
  if (x === 'MODERATE' || x === 'ELEVATED') return 6.5;
  if (x === 'WATCH' || x === 'LIMITED') return 5.0;
  return 4.0;
};

const intensityScore = (v) => {
  const x = safe(v).toUpperCase();
  if (x === 'SURGE') return 8.8;
  if (x === 'ELEVATED') return 7.0;
  if (x === 'WATCH') return 5.2;
  return 4.0;
};

const escalationRank = { MONITOR: 0, STANDARD: 1, SENIOR: 2, EXECUTIVE: 3 };
const routeRank = {
  DISMISS: 0,
  LOW: 1,
  MED: 2,
  MED_ELEVATED: 3,
  HIGH: 4,
  HIGH_COMPETITOR: 5,
  SAFETY_ESCALATION: 6,
  CRITICAL: 7,
  AI_FAILED: -1,
  DB_FAILED: -1
};

const routePriority = {
  CRITICAL: 'P0',
  SAFETY_ESCALATION: 'P0',
  HIGH_COMPETITOR: 'P1',
  HIGH: 'P1',
  MED_ELEVATED: 'P2',
  MED: 'P3',
  LOW: 'P4',
  DISMISS: 'P5'
};

const routeChannels = {
  CRITICAL: ['pharmaos-critical', 'pharmaos-executive', 'email_exec', 'pagerduty'],
  SAFETY_ESCALATION: ['pharmaos-critical', 'pharmaos-safety', 'pharmaos-executive', 'email_safety', 'pagerduty'],
  HIGH_COMPETITOR: ['pharmaos-ci-team', 'pharmaos-medical-affairs', 'email_ci_team'],
  HIGH: ['pharmaos-medical-affairs', 'pharmaos-ci-team'],
  MED_ELEVATED: ['pharmaos-ci-team'],
  MED: ['digest_daily'],
  LOW: ['digest_weekly'],
  DISMISS: ['archive']
};

const sourceCtx = {
  route_tier: safe(sourceSignal.route_tier, 'LOW'),
  notif_priority: safe(sourceSignal.notif_priority, 'P4'),
  priority_score: num(sourceSignal.priority_score, num(sourceSignal.impact_score, 0)),
  impact_score: num(sourceSignal.impact_score, 0),
  impact_level: safe(sourceSignal.impact_level, 'LOW').toUpperCase(),
  signal_domain: safe(sourceSignal.signal_domain, 'ci'),
  signal_type: safe(sourceSignal.signal_type, 'other'),
  is_urgent: bool(sourceSignal.is_urgent),
  competitor_flag: bool(sourceSignal.competitor_flag),
  confidence_score: confidenceBandScore(sourceSignal.confidence),
  quality_score: num(sourceSignal._triage_meta && sourceSignal._triage_meta.quality_score, num(sourceSignal.quality_score, 5)),
  asset_id: safe(sourceSignal.asset_id || sourceSignal.assetid),
  drug_name: safe(sourceSignal.drug_name || sourceSignal.drugname || sourceSignal.entity_name),
  indication: safe(sourceSignal.indication),
  sponsor: safe(sourceSignal.sponsor),
  alert_channels: arr(sourceSignal.alert_channels)
};

const dbResult = {
  triple_threats: arr(prep.triple_threats),
  recall_cascades: arr(prep.recall_cascades),
  competitive_surges: arr(prep.competitive_surges),
  ghost_clusters: arr(prep.ghost_clusters),
  pipeline_accelerations: arr(prep.pipeline_accelerations),
  total_compound_events: num(prep.total_events, 0)
};

dbResult.triplethreats = dbResult.triple_threats;
dbResult.recallcascades = dbResult.recall_cascades;
dbResult.competitivesurges = dbResult.competitive_surges;
dbResult.ghostclusters = dbResult.ghost_clusters;
dbResult.pipelineaccelerations = dbResult.pipeline_accelerations;
dbResult.totalcompoundevents = dbResult.total_compound_events;

const strategicOverlap = (meta) => {
  let score = 0;
  const hits = [];

  const srcAsset = safe(sourceCtx.asset_id);
  const srcDrug = low(sourceCtx.drug_name);
  const srcInd = low(sourceCtx.indication);

  const assetIds = uniq((meta.asset_ids || meta.assetids || [])).map(String);
  const drugNames = uniq((meta.drug_names || meta.drugnames || [])).map(x => low(x));
  const indications = uniq((meta.indications || [])).map(x => low(x));
  const affectedEntity = low(meta.affected_entity || meta.pipeline_entity || meta.indication || '');

  if (srcAsset && assetIds.includes(srcAsset)) {
    score += 1.6;
    hits.push('asset_match');
  }
  if (srcDrug && (drugNames.includes(srcDrug) || affectedEntity === srcDrug)) {
    score += 1.2;
    hits.push('drug_match');
  }
  if (srcInd && (indications.includes(srcInd) || low(meta.indication) === srcInd || affectedEntity === srcInd)) {
    score += 0.9;
    hits.push('indication_match');
  }

  return {
    score: round2(clamp(score, 0, 2.7)),
    hits
  };
};

const baseEvent = (type, title, triggerPattern, domains, patternMetadata) => ({
  event_type: type,
  title,
  trigger_pattern: triggerPattern,
  domains: uniq(domains),
  pattern_metadata: patternMetadata,
  detected_at: nowIso()
});

const buildTripleThreat = (t) => {
  const overlap = strategicOverlap(t);
  const domainCount = num(t.domain_count, 0);
  const totalSignals = num(t.total_signals, 0);
  const peak = num(t.peak_impact, 0);
  const avg = num(t.avg_impact, peak);
  const richness = num(t.total_richness, 0);
  const recency = recencyScore(t.latest_signal_at, 96);

  const match = safe(t.match_confidence, 'DOMAIN_ONLY').toUpperCase();
  const matchBoost = {
    EXACT_ASSET: 1.8,
    DRUG_NAME: 1.2,
    ENTITY_NAME: 0.9,
    INDICATION_CLUSTER: 0.6,
    DOMAIN_ONLY: 0.2
  }[match] || 0.2;

  const risk = clamp10(
    (peak * 0.36) +
    (avg * 0.12) +
    (domainCount * 0.95) +
    (Math.min(totalSignals, 12) * 0.13) +
    (Math.min(richness, 40) * 0.05) +
    (recency * 0.18) +
    matchBoost +
    overlap.score
  );

  const confidence = clamp01(
    0.34 +
    (Math.min(domainCount, 5) * 0.08) +
    (Math.min(totalSignals, 10) * 0.02) +
    (Math.min(richness, 30) * 0.008) +
    (matchBoost * 0.05)
  );

  const escalation =
    domainCount >= 4 || match === 'EXACT_ASSET' || risk >= 8.7 ? 'EXECUTIVE' :
    risk >= 6.8 ? 'SENIOR' : 'STANDARD';

  const entityLabel =
    arr(t.drug_names)[0] ||
    arr(t.asset_ids)[0] ||
    arr(t.entity_names)[0] ||
    arr(t.indications)[0] ||
    safe(t.entity_key, 'Unknown entity');

  return {
    ...baseEvent(
      'TRIPLE_THREAT',
      `TRIPLE_THREAT: ${entityLabel} across ${domainCount} domains`,
      'ASSET_TRIPLE_THREAT',
      arr(t.domains),
      t
    ),
    escalation_level: escalation,
    compound_risk_score: round2(risk),
    confidence_score: round2(confidence),
    urgency_score: round2((recency * 0.7) + (sourceCtx.is_urgent ? 1.4 : 0.3)),
    evidence_strength: round2(clamp10((domainCount * 1.3) + (totalSignals * 0.18) + (richness * 0.06))),
    strategic_relevance: round2(clamp10((overlap.score * 3.2) + (sourceCtx.competitor_flag ? 1.0 : 0.2))),
    executive_score: round2(clamp10((risk * 0.75) + (match === 'EXACT_ASSET' ? 1.6 : 0))),
    risk_drivers: uniq([
      `Cross-domain breadth: ${domainCount}`,
      `Peak impact: ${peak}`,
      totalSignals ? `Signal count: ${totalSignals}` : null,
      match !== 'DOMAIN_ONLY' ? `Entity confidence: ${match}` : null,
      overlap.hits.length ? `Portfolio overlap: ${overlap.hits.join(', ')}` : null
    ]),
    caveats: uniq([
      match === 'DOMAIN_ONLY' ? 'Entity linkage is broad rather than asset-exact' : null,
      totalSignals < 3 ? 'Low supporting signal count' : null
    ]),
    recommended_actions: uniq([
      'Cross-domain analyst review',
      'Validate entity resolution and asset linkage',
      'Prepare CI escalation note',
      sourceCtx.competitor_flag ? 'Update competitor monitoring board' : null
    ])
  };
};

const buildRecallCascade = (r) => {
  const overlap = strategicOverlap(r);
  const severity = safe(r.severity, 'HIGH').toUpperCase();
  const sev = severityScore(severity);
  const peak = num(r.peak_impact, 0);
  const total = num(r.total_safety_signals, 0);
  const typeCount = num(r.safety_type_count, arr(r.safety_types).length);
  const cascadeHours = num(r.cascade_hours, 48);
  const speedScore = clamp10(10 - Math.min(cascadeHours, 72) / 72 * 10);
  const recency = recencyScore(r.latest_signal_at, 72);

  const risk = clamp10(
    (sev * 0.42) +
    (peak * 0.18) +
    (Math.min(total, 8) * 0.22) +
    (Math.min(typeCount, 4) * 0.65) +
    (speedScore * 0.24) +
    (recency * 0.16) +
    overlap.score
  );

  const confidence = clamp01(
    0.48 +
    (Math.min(typeCount, 4) * 0.07) +
    (Math.min(total, 6) * 0.03) +
    (severity === 'CRITICAL' ? 0.12 : severity === 'HIGH' ? 0.08 : 0.04)
  );

  const escalation =
    severity === 'CRITICAL' || risk >= 8.6 ? 'EXECUTIVE' :
    risk >= 6.7 ? 'SENIOR' : 'STANDARD';

  return {
    ...baseEvent(
      'RECALL_CASCADE',
      `RECALL_CASCADE: ${safe(r.affected_entity, 'Unknown')} (${arr(r.safety_types).join(' + ')})`,
      'RECALL_SAFETY_CASCADE',
      ['safety', 'regulatory'],
      r
    ),
    escalation_level: escalation,
    compound_risk_score: round2(risk),
    confidence_score: round2(confidence),
    urgency_score: round2((recency * 0.6) + (speedScore * 0.3) + (sourceCtx.is_urgent ? 1.0 : 0.4)),
    evidence_strength: round2(clamp10((typeCount * 1.5) + (total * 0.5) + (sev * 0.25))),
    strategic_relevance: round2(clamp10((overlap.score * 3.0) + 3.2)),
    executive_score: round2(clamp10((risk * 0.82) + (severity === 'CRITICAL' ? 1.4 : 0.5))),
    risk_drivers: uniq([
      `Safety severity: ${severity}`,
      `Safety type count: ${typeCount}`,
      total ? `Supporting safety signals: ${total}` : null,
      cascadeHours ? `Cascade window: ${round2(cascadeHours)}h` : null
    ]),
    caveats: uniq([
      total < 2 ? 'Limited number of corroborating safety records' : null
    ]),
    recommended_actions: uniq([
      'Immediate safety review',
      'Regulatory impact check',
      'Prepare executive alert if patient impact broadens',
      'Review recall / label / adverse event linkage'
    ])
  };
};

const buildCompetitiveSurge = (c) => {
  const overlap = strategicOverlap(c);
  const intensity = safe(c.intensity, 'WATCH').toUpperCase();
  const inten = intensityScore(intensity);
  const hitCount = num(c.hit_count, 0);
  const competitorCount = num(c.competitor_count, 0);
  const avgImpact = num(c.avg_impact, num(c.peak_impact, 0));
  const peak = num(c.peak_impact, avgImpact);
  const recency = recencyScore(c.latest_signal_at, 36);

  const risk = clamp10(
    (inten * 0.32) +
    (avgImpact * 0.22) +
    (peak * 0.12) +
    (Math.min(hitCount, 15) * 0.18) +
    (Math.min(competitorCount, 8) * 0.20) +
    (recency * 0.18) +
    overlap.score +
    (sourceCtx.competitor_flag ? 0.8 : 0.2)
  );

  const confidence = clamp01(
    0.32 +
    (Math.min(hitCount, 12) * 0.025) +
    (Math.min(competitorCount, 6) * 0.04) +
    (intensity === 'SURGE' ? 0.10 : intensity === 'ELEVATED' ? 0.06 : 0.02)
  );

  const escalation =
    intensity === 'SURGE' || risk >= 8.2 ? 'SENIOR' :
    risk >= 5.8 ? 'STANDARD' : 'MONITOR';

  return {
    ...baseEvent(
      'COMPETITIVE_SURGE',
      `COMPETITIVE_SURGE: ${hitCount} competitor signals in ${safe(c.indication, 'Unknown indication')}`,
      'COMPETITIVE_SURGE',
      arr(c.domains).length ? arr(c.domains) : ['ci'],
      c
    ),
    escalation_level: escalation,
    compound_risk_score: round2(risk),
    confidence_score: round2(confidence),
    urgency_score: round2((recency * 0.65) + (sourceCtx.competitor_flag ? 1.0 : 0.2)),
    evidence_strength: round2(clamp10((hitCount * 0.45) + (competitorCount * 0.7) + (avgImpact * 0.25))),
    strategic_relevance: round2(clamp10((overlap.score * 3.5) + (sourceCtx.competitor_flag ? 2.2 : 0.8))),
    executive_score: round2(clamp10((risk * 0.65) + (intensity === 'SURGE' ? 0.9 : 0.2))),
    risk_drivers: uniq([
      `Intensity: ${intensity}`,
      `Hit count: ${hitCount}`,
      competitorCount ? `Competitor breadth: ${competitorCount}` : null,
      avgImpact ? `Average impact: ${round2(avgImpact)}` : null
    ]),
    caveats: uniq([
      competitorCount < 2 ? 'Surge may be concentrated in few competitors' : null
    ]),
    recommended_actions: uniq([
      'Refresh indication battlefield',
      'Update competitor watchlist',
      'Add to portfolio review',
      'Check for launch-timing implications'
    ])
  };
};

const buildGhostCluster = (g) => {
  const peak = num(g.peak_impact, 0);
  const avgImpact = num(g.avg_impact, peak);
  const clusterSize = num(g.cluster_size, 0);
  const urgentCount = num(g.urgent_count, 0);
  const recency = recencyScore(g.window_end || g.latest_signal_at, 30);

  const opacityPenalty = 1.2 + (urgentCount > 0 ? 0.8 : 0) + (peak >= 8 ? 0.6 : 0);

  const risk = clamp10(
    (peak * 0.26) +
    (avgImpact * 0.20) +
    (Math.min(clusterSize, 10) * 0.30) +
    (Math.min(urgentCount, 5) * 0.65) +
    (recency * 0.20) +
    opacityPenalty
  );

  const confidence = clamp01(
    0.26 +
    (Math.min(clusterSize, 10) * 0.03) +
    (urgentCount > 0 ? 0.10 : 0.03)
  );

  const escalation =
    urgentCount > 0 || peak >= 8.5 || risk >= 7.6 ? 'SENIOR' :
    risk >= 5.5 ? 'STANDARD' : 'MONITOR';

  return {
    ...baseEvent(
      'GHOST_CLUSTER',
      `GHOST_CLUSTER: ${clusterSize} unidentified ${safe(g.signal_type, 'signal')} records in ${safe(g.signal_domain, 'unknown')}`,
      'GHOST_CLUSTER',
      [safe(g.signal_domain, 'unknown')],
      g
    ),
    escalation_level: escalation,
    compound_risk_score: round2(risk),
    confidence_score: round2(confidence),
    urgency_score: round2((recency * 0.55) + (urgentCount * 0.7)),
    evidence_strength: round2(clamp10((clusterSize * 0.55) + (avgImpact * 0.3))),
    strategic_relevance: round2(clamp10((sourceCtx.quality_score < 6 ? 2.0 : 0.8) + (peak * 0.25))),
    executive_score: round2(clamp10((risk * 0.58) + (urgentCount > 0 ? 1.1 : 0))),
    risk_drivers: uniq([
      `Cluster size: ${clusterSize}`,
      urgentCount ? `Urgent records: ${urgentCount}` : null,
      peak ? `Peak impact: ${peak}` : null,
      'Identifier opacity may hide critical entities'
    ]),
    caveats: uniq([
      'Entity identity unresolved',
      'Requires enrichment before root-cause confidence improves'
    ]),
    recommended_actions: uniq([
      'Manual enrichment required',
      'Check missing asset / drug / entity mapping',
      'Review ingestion parser quality',
      'Backfill identifiers before executive reporting'
    ])
  };
};

const buildPipelineAcceleration = (p) => {
  const overlap = strategicOverlap(p);
  const peak = num(p.peak_impact, 0);
  const signalCount = num(p.signal_count, 0);
  const trialCount = num(p.trial_count, 0);
  const phaseBreadth = arr(p.phases_observed).length;
  const recency = recencyScore(p.latest_signal_at, 60);

  const risk = clamp10(
    (peak * 0.31) +
    (Math.min(trialCount, 6) * 0.45) +
    (Math.min(signalCount, 10) * 0.18) +
    (Math.min(phaseBreadth, 5) * 0.55) +
    (recency * 0.18) +
    overlap.score
  );

  const confidence = clamp01(
    0.30 +
    (Math.min(trialCount, 5) * 0.05) +
    (Math.min(signalCount, 8) * 0.025) +
    (phaseBreadth >= 2 ? 0.10 : 0.04)
  );

  const escalation =
    risk >= 7.9 ? 'SENIOR' :
    risk >= 5.7 ? 'STANDARD' : 'MONITOR';

  return {
    ...baseEvent(
      'PIPELINE_ACCELERATION',
      `PIPELINE_ACCELERATION: ${safe(p.pipeline_entity, 'Unknown')} with ${signalCount} signals`,
      'PIPELINE_ACCELERATION',
      ['ct_gov', 'regulatory'],
      p
    ),
    escalation_level: escalation,
    compound_risk_score: round2(risk),
    confidence_score: round2(confidence),
    urgency_score: round2((recency * 0.6) + (trialCount * 0.3)),
    evidence_strength: round2(clamp10((trialCount * 0.9) + (signalCount * 0.25) + (phaseBreadth * 0.8))),
    strategic_relevance: round2(clamp10((overlap.score * 3.3) + 1.2)),
    executive_score: round2(clamp10((risk * 0.62) + (trialCount >= 3 ? 0.8 : 0))),
    risk_drivers: uniq([
      trialCount ? `Trial count: ${trialCount}` : null,
      signalCount ? `Signal count: ${signalCount}` : null,
      phaseBreadth ? `Phase breadth: ${phaseBreadth}` : null,
      peak ? `Peak impact: ${peak}` : null
    ]),
    caveats: uniq([
      phaseBreadth < 2 ? 'Phase movement evidence may still be narrow' : null
    ]),
    recommended_actions: uniq([
      'Update pipeline tracker',
      'Reassess launch timing assumptions',
      'Check competitive overlap',
      'Refresh asset-level forecast scenarios'
    ])
  };
};

const allEvents = [
  ...dbResult.triple_threats.map(buildTripleThreat),
  ...dbResult.recall_cascades.map(buildRecallCascade),
  ...dbResult.competitive_surges.map(buildCompetitiveSurge),
  ...dbResult.ghost_clusters.map(buildGhostCluster),
  ...dbResult.pipeline_accelerations.map(buildPipelineAcceleration)
];

const escalationLevelOf = (e) => safe(e.escalation_level, 'MONITOR').toUpperCase();

allEvents.sort((a, b) => {
  const er = escalationRank[escalationLevelOf(b)] - escalationRank[escalationLevelOf(a)];
  if (er !== 0) return er;
  return num(b.compound_risk_score, 0) - num(a.compound_risk_score, 0);
});

const eventTypeCounts = allEvents.reduce((acc, e) => {
  acc[e.event_type] = (acc[e.event_type] || 0) + 1;
  return acc;
}, {});

const activeEventTypes = Object.keys(eventTypeCounts).length;
const maxRisk = allEvents.length ? Math.max(...allEvents.map(e => num(e.compound_risk_score, 0))) : 0;
const avgRisk = allEvents.length ? round2(allEvents.reduce((s, e) => s + num(e.compound_risk_score, 0), 0) / allEvents.length) : 0;
const executiveCount = allEvents.filter(e => escalationLevelOf(e) === 'EXECUTIVE').length;
const seniorCount = allEvents.filter(e => escalationLevelOf(e) === 'SENIOR').length;
const hasCriticalRecall = allEvents.some(e => e.event_type === 'RECALL_CASCADE' && safe(e.pattern_metadata.severity).toUpperCase() === 'CRITICAL');
const hasSafetySignal = allEvents.some(e => e.domains.includes('safety')) || sourceCtx.signal_domain === 'safety';

const synergies = [];

if (eventTypeCounts.TRIPLE_THREAT && eventTypeCounts.RECALL_CASCADE) {
  synergies.push({
    synergy_type: 'SAFETY_PORTFOLIO_CONVERGENCE',
    synergy_score: 9.2,
    description: 'Cross-domain strategic convergence is colliding with safety/regulatory pressure.'
  });
}
if (eventTypeCounts.COMPETITIVE_SURGE && eventTypeCounts.PIPELINE_ACCELERATION) {
  synergies.push({
    synergy_type: 'COMPETITIVE_LAUNCH_PRESSURE',
    synergy_score: 8.1,
    description: 'Competitor signal density and pipeline acceleration point to near-term battlefield compression.'
  });
}
if (eventTypeCounts.GHOST_CLUSTER && (executiveCount > 0 || hasCriticalRecall)) {
  synergies.push({
    synergy_type: 'DATA_OPACITY_ON_HIGH_RISK_SIGNAL',
    synergy_score: 8.6,
    description: 'High-risk signal cluster is present while entity resolution remains incomplete.'
  });
}
if (activeEventTypes >= 3) {
  synergies.push({
    synergy_type: 'MULTI_VECTOR_SIGNAL_CONVERGENCE',
    synergy_score: 8.8,
    description: 'Multiple compound signal classes are co-occurring in the same monitoring window.'
  });
}

const portfolioThreatIndex = round2(clamp10(
  (avgRisk * 0.42) +
  (maxRisk * 0.33) +
  (activeEventTypes * 0.65) +
  (executiveCount * 0.70) +
  (synergies.length * 0.45) +
  (sourceCtx.priority_score * 0.06)
));

const systemicRiskIndex = round2(clamp10(
  (activeEventTypes * 1.20) +
  (synergies.length * 1.30) +
  (executiveCount > 0 ? 2.0 : 0) +
  (hasCriticalRecall ? 1.8 : 0) +
  (eventTypeCounts.GHOST_CLUSTER ? 0.7 : 0)
));

const derivedAlertScore = round2(
  allEvents.reduce((sum, e) => {
    const w = {
      TRIPLE_THREAT: 8,
      RECALL_CASCADE: 10,
      COMPETITIVE_SURGE: 6,
      GHOST_CLUSTER: 4,
      PIPELINE_ACCELERATION: 5
    }[e.event_type] || 4;
    return sum + (num(e.compound_risk_score, 0) * w);
  }, 0) + synergies.reduce((s, x) => s + (num(x.synergy_score, 0) * 5), 0)
);

const compoundAlertScore = round2(Math.max(num(prep.alert_score, 0), derivedAlertScore));

let escalationLevel = 'MONITOR';
if (executiveCount > 0 || hasCriticalRecall || portfolioThreatIndex >= 8.5 || compoundAlertScore >= 160) {
  escalationLevel = 'EXECUTIVE';
} else if (seniorCount > 0 || portfolioThreatIndex >= 6.7 || systemicRiskIndex >= 7.0 || compoundAlertScore >= 95) {
  escalationLevel = 'SENIOR';
} else if (allEvents.length > 0) {
  escalationLevel = 'STANDARD';
}

const currentRoute = safe(sourceCtx.route_tier, 'LOW').toUpperCase();

const candidateRoute = (() => {
  if (escalationLevel === 'EXECUTIVE') {
    return hasSafetySignal ? 'SAFETY_ESCALATION' : 'CRITICAL';
  }
  if (escalationLevel === 'SENIOR') {
    return sourceCtx.competitor_flag ? 'HIGH_COMPETITOR' : 'HIGH';
  }
  if (escalationLevel === 'STANDARD') {
    return 'MED_ELEVATED';
  }
  return currentRoute;
})();

const finalRoute =
  (routeRank[candidateRoute] || 0) > (routeRank[currentRoute] || 0)
    ? candidateRoute
    : currentRoute;

const finalNotifPriority = routePriority[finalRoute] || safe(sourceCtx.notif_priority, 'P4');

const involvedDomains = uniq(
  allEvents.flatMap(e => arr(e.domains)).concat([sourceCtx.signal_domain])
);

const finalChannels = (() => {
  const base = uniq((routeChannels[finalRoute] || []).concat(sourceCtx.alert_channels));
  if (involvedDomains.includes('safety') && !base.includes('pharmaos-safety')) base.push('pharmaos-safety');
  if (sourceCtx.competitor_flag && !base.includes('pharmaos-ci-team')) base.push('pharmaos-ci-team');
  if ((executiveCount > 0 || finalRoute === 'CRITICAL' || finalRoute === 'SAFETY_ESCALATION') && !base.includes('pagerduty')) base.push('pagerduty');
  return uniq(base);
})();

const overrideRecommended = finalRoute !== currentRoute;
const totalEvents = dbResult.total_compound_events || allEvents.length;

return [{
  json: {
    ...prep,
    source_signal: sourceSignal,

    compound_db_result: dbResult,

    compound_events_detected: allEvents,
    has_compound_event: allEvents.length > 0,

    compound_total_events: totalEvents,
    compound_alert_score: compoundAlertScore,
    compound_escalation_level: escalationLevel,
    compound_max_risk: round2(maxRisk),
    compound_avg_risk: round2(avgRisk),
    compound_portfolio_threat_index: portfolioThreatIndex,
    compound_systemic_risk_index: systemicRiskIndex,
    compound_event_type_counts: eventTypeCounts,
    compound_synergies: synergies,

    compound_recommended_route: finalRoute,
    compound_recommended_notif_priority: finalNotifPriority,
    compound_recommended_channels: finalChannels,
    compound_route_override_recommended: overrideRecommended,

    totalcompoundevents: totalEvents,
    alertscore: compoundAlertScore,
    escalationlevel: escalationLevel,
    hascritical: hasCriticalRecall,

    triplethreats: dbResult.triple_threats,
    recallcascades: dbResult.recall_cascades,
    competitivesurges: dbResult.competitive_surges,
    ghostclusters: dbResult.ghost_clusters,
    pipelineaccelerations: dbResult.pipeline_accelerations,

    _compound_check: {
      checked_at: nowIso(),
      current_route: currentRoute,
      candidate_route: candidateRoute,
      final_route: finalRoute,
      override_recommended: overrideRecommended,
      executive_count: executiveCount,
      senior_count: seniorCount,
      active_event_types: activeEventTypes,
      involved_domains: involvedDomains,
      source_context: sourceCtx,
      logic_version: '6.1.0-advanced'
    }
  }
}];
